components.render:
const { label='Label', type='text', value='', placeholder='', state='default', error='' } = props || {};
const isError = state === 'error';
return `
  <label class="field" style="display:flex;flex-direction:column;gap:6px;font-family:var(--font-body);">
    <span class="field__label" style="font-size:13px;font-weight:600;color:var(--text-active-secondary);">${label}</span>
    <input class="field__input" type="${type}" value="${value}" placeholder="${placeholder}"
           style="height:44px;padding:0 14px;border-radius:var(--pg-radius-small);
                  border:1px solid ${isError ? '#d92d20' : 'var(--border-strong)'};
                  background:var(--pg-gray-0);font-size:15px;color:var(--text-active-primary);
                  outline:none;transition:border-color .12s,box-shadow .12s;" />
    ${isError ? `<span class="field__error" style="font-size:12px;color:#d92d20;">${error}</span>` : ``}
  </label>`;

const { label='Button', variant='primary', size='md', disabled=false, fullWidth=false } = props || {};
const pad = size === 'lg' ? '0 24px' : size === 'sm' ? '0 14px' : '0 18px';
const height = size === 'lg' ? '48px' : size === 'sm' ? '32px' : '40px';
const bg = variant === 'primary' ? 'var(--fill-active-primary)' : 'transparent';
const fg = variant === 'primary' ? 'var(--pg-gray-0)' : 'var(--text-active-primary)';
const bd = variant === 'secondary' ? '1px solid var(--border-strong)' : 'none';
return `
  <button class="btn btn--${variant}" ${disabled ? 'disabled' : ''}
          style="height:${height};padding:${pad};${fullWidth ? 'width:100%;' : ''}
                 display:inline-flex;align-items:center;justify-content:center;gap:8px;
                 border-radius:var(--pg-radius-small);border:${bd};background:${bg};color:${fg};
                 font-family:var(--font-body);font-size:15px;font-weight:600;cursor:pointer;
                 opacity:${disabled ? '0.5' : '1'};transition:background .12s,border-color .12s;">
    <span class="btn__label">${label}</span>
  </button>`;

const { length=6, value='', state='default' } = props || {};
const isError = state === 'error';
let boxes = '';
for (let i = 0; i < length; i++) {
  boxes += `<input class="otp__box" inputmode="numeric" maxlength="1" value="${value[i] || ''}"
             style="width:44px;height:52px;text-align:center;font-size:20px;font-family:var(--font-body);
                    border-radius:var(--pg-radius-small);background:var(--pg-gray-0);
                    border:1px solid ${isError ? 'var(--danger)' : 'var(--border-strong)'};outline:none;" />`;
}
return `<div class="otp" style="display:flex;flex-direction:column;gap:8px;align-items:center;"><div style="display:flex;gap:8px;">${boxes}</div>${isError ? `<span class="otp__error" style="font-size:12px;color:var(--danger);">Code is incorrect.</span>` : ``}</div>`;

screens.render:
return `
  <section class="screen screen--signin"
           style="max-width:380px;margin:0 auto;display:flex;flex-direction:column;gap:16px;
                  padding:32px;background:var(--pg-gray-0);border-radius:var(--pg-radius-medium);
                  box-shadow:var(--hive-shadow-soft-md);">
    <h1 class="screen__title" style="margin:0;font-family:var(--font-heading);font-size:24px;
               font-weight:700;color:var(--text-active-primary);">Sign in</h1>
    <p class="screen__subtitle" style="margin:0;font-size:14px;color:var(--text-active-secondary);">
      Welcome back. Enter your details to continue.</p>
    ${renderCmpTextInput({ label:'Email', type:'email', placeholder:'you@company.com' })}
    ${renderCmpTextInput({ label:'Password', type:'password', placeholder:'••••••••' })}
    ${renderCmpButton({ label:'Sign in', variant:'primary', size:'md', fullWidth:true })}
    <a class="screen__link" href="#" style="align-self:center;font-size:13px;color:var(--brand);
       text-decoration:none;">Forgot password?</a>
  </section>`;

return `
